INSERT INTO phishing_scenarios (sender_name, sender_email, subject_line, email_body_html, persuasion_principle, difficulty_level, is_phishing, assessment_set) VALUES
('ABUAD ICT Department', 'ict-support@abuad-portal.net', 'URGENT: Your Student Portal Access Will Be Revoked',
'<div style="font-family:Arial,sans-serif;padding:20px;"><p>Dear Student,</p><p>We have detected unusual activity on your student portal account. For security reasons, your access will be <strong>permanently revoked within 24 hours</strong> unless you verify your identity immediately.</p><p>Click the link below to verify your account:</p><p><a href="#" style="color:#0066cc;">https://abuad-portal.net/verify-account</a></p><p>Failure to comply will result in loss of access to all academic services.</p><p>Regards,<br/>ICT Support Team<br/>Afe Babalola University</p></div>',
'authority', 1, true, 'pre');

