-- ============================================
-- TRAINING MODULE CONTENT
-- ============================================

-- Module A: Text-based training (Group 1)
INSERT INTO training_modules (group_id, title, content_type, content_body, display_order) VALUES
(1, 'Understanding Phishing and Social Engineering', 'text',
'<div style="font-family:Arial,sans-serif;max-width:800px;margin:0 auto;padding:20px;line-height:1.8;"><h2 style="color:#1a365d;border-bottom:2px solid #0d9488;padding-bottom:8px;">1. What is Phishing?</h2><p>Phishing is a type of cyber attack where someone pretends to be a trusted person or organisation to trick you into giving away sensitive information — passwords, bank details, or personal data. The attacker usually contacts you through email, but phishing can also happen through text messages, phone calls, or social media.</p><p>Think of it like a con artist who dresses up as a bank employee and asks for your ATM PIN. The uniform looks real, the ID badge looks real, but the person is a fraud. Phishing works the same way — except it happens on your screen.</p><h2 style="color:#1a365d;border-bottom:2px solid #0d9488;padding-bottom:8px;">2. Why Should You Care?</h2><p>University students are prime targets. You receive dozens of emails every week about scholarships, exam schedules, course registration, and campus events. Attackers know this, and they craft fake emails that blend right into your inbox. In 2023 alone, nearly 5 million phishing attacks were recorded worldwide. Universities are among the most frequently targeted institutions.</p><h2 style="color:#1a365d;border-bottom:2px solid #0d9488;padding-bottom:8px;">3. How Attackers Trick You</h2><div style="background:#f0fdfa;padding:16px;border-left:4px solid #0d9488;margin:12px 0;"><p><strong style="color:#0d9488;">Authority:</strong> The email appears to come from someone important — the Registrar, the IT department, your Dean. You are conditioned to take such emails seriously and act quickly.</p></div><div style="background:#fef3c7;padding:16px;border-left:4px solid #f59e0b;margin:12px 0;"><p><strong style="color:#d97706;">Urgency:</strong> "Your account will be suspended in 24 hours." This pressure makes you act before you think.</p></div><div style="background:#ede9fe;padding:16px;border-left:4px solid #8b5cf6;margin:12px 0;"><p><strong style="color:#7c3aed;">Scarcity:</strong> "Only 50 scholarship slots remaining." The fear of missing out pushes you to click without checking.</p></div><div style="background:#dbeafe;padding:16px;border-left:4px solid #3b82f6;margin:12px 0;"><p><strong style="color:#2563eb;">Social Proof:</strong> "Over 1,000 students have already verified their accounts." If everyone else did it, it must be safe — right?</p></div><h2 style="color:#1a365d;border-bottom:2px solid #0d9488;padding-bottom:8px;">4. Red Flags to Watch For</h2><p><strong>1. Check the sender''s email address carefully.</strong> The name might say "ABUAD Registrar" but the actual address might be <code>registrar@abuad-portal.net</code> instead of <code>@abuad.edu.ng</code>. Always look at what comes after the @ sign.</p><p><strong>2. Hover over links before clicking.</strong> The actual URL will appear at the bottom of your browser. If it does not match where the email claims to send you, do not click.</p><p><strong>3. Watch for generic greetings.</strong> "Dear Student" or "Dear User" often signals a mass-sent fake.</p><p><strong>4. Be suspicious of pressure language.</strong> "Immediately," "within 24 hours," "your account will be locked" — these are designed to make you panic.</p><p><strong>5. Look for spelling errors.</strong> Words like "thier" instead of "their" or "recieve" instead of "receive."</p><p><strong>6. Question unexpected requests.</strong> Would the IT department really ask you to "verify your password" via email?</p><p><strong>7. Check for mismatched tone.</strong> An unusually casual email from the Registrar, or an oddly formal personal message, may be fake.</p><h2 style="color:#1a365d;border-bottom:2px solid #0d9488;padding-bottom:8px;">5. What To Do</h2><div style="background:#f0fdf4;padding:16px;border-radius:8px;margin:12px 0;"><p><strong>Do not click</strong> any links or download attachments.</p><p><strong>Do not reply.</strong> Responding confirms your email is active.</p><p><strong>Verify independently.</strong> Go directly to the official website by typing the URL yourself, or call the office.</p><p><strong>Report it.</strong> Forward to your university IT department.</p><p><strong>Delete it.</strong> Once reported, remove it from your inbox.</p></div></div>',
1);

-- Module B: Video-based training (Group 2)
INSERT INTO training_modules (group_id, title, content_type, content_body, display_order) VALUES
(2, 'Phishing Awareness Video Series', 'video',
'[{"title":"What is Phishing and Why Should You Care?","url":"https://www.youtube.com/embed/XBkzBrXlle0","duration":"3:45","description":"Introduction to phishing attacks, why university students are targeted, and the scale of the problem globally and in Nigeria."},{"title":"The Psychology Behind Phishing Attacks","url":"https://www.youtube.com/embed/XBkzBrXlle0","duration":"4:10","description":"How attackers exploit authority, urgency, scarcity, and social proof to bypass your defences. Real examples of each tactic."},{"title":"Spotting the Red Flags: A Live Demonstration","url":"https://www.youtube.com/embed/XBkzBrXlle0","duration":"5:00","description":"Step-by-step screen-capture walkthrough: examining sender addresses, hovering over links, checking domains, and identifying suspicious patterns."},{"title":"What To Do When You Suspect Phishing","url":"https://www.youtube.com/embed/XBkzBrXlle0","duration":"3:00","description":"Practical steps: do not click, verify independently, report to IT, and protect your accounts."}]',
1);

-- Module C: Interactive quiz-based training (Group 3) — 15 SCENARIOS
-- Scaffolded: Easy (1-5) → Medium (6-10) → Hard (11-15)
-- Mix of phishing and legitimate, covering all 4 principles
INSERT INTO training_modules (group_id, title, content_type, content_body, display_order) VALUES
(3, 'Interactive Phishing Detection Training', 'interactive',
'[
{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD IT Support &lt;support@abuad-itsupport.net&gt;</p><p><strong>Subject:</strong> Your Email Storage Is Full</p><hr/><p>Dear Student,</p><p>Your university email has reached its storage limit. You will not be able to receive new emails until you clear space or upgrade your account.</p><p>Click here to upgrade: <a href=\"#\">https://abuad-itsupport.net/upgrade</a></p><p>IT Support Team</p></div>","is_phishing":true,"correct_feedback":"Correct! The domain abuad-itsupport.net is not the real abuad.edu.ng. ABUAD uses Google Workspace — storage issues would be handled through Google, not a custom link.","incorrect_feedback":"This is phishing. The sender domain abuad-itsupport.net is fake. The real university domain is abuad.edu.ng. Always check the domain after the @ sign.","principle":"authority","difficulty":1},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> Department of Computing &lt;computing@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> Reminder: Submit Your Lab Report</p><hr/><p>Dear Students,</p><p>This is a reminder that CSC 303 lab reports are due on Friday. Please submit hard copies to the departmental office before 4 PM.</p><p>Late submissions attract a penalty of 5 marks per day.</p><p>Thank you.<br/>Department of Computing</p></div>","is_phishing":false,"correct_feedback":"Correct! This is legitimate. The sender is computing@abuad.edu.ng (real domain), no suspicious links, and the request is to submit a physical document.","incorrect_feedback":"This is legitimate. The real domain abuad.edu.ng is used, there are no links to click, and the instruction is to submit a hard copy in person.","principle":"authority","difficulty":1},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Bursary &lt;bursary@abuad-finance.org&gt;</p><p><strong>Subject:</strong> Urgent: Outstanding Fees Notification</p><hr/><p>Dear Student,</p><p>Our records indicate you have an outstanding balance of N45,000. <strong>If not resolved within 48 hours, your exam eligibility will be revoked.</strong></p><p>Make payment or verify your account here:</p><p><a href=\"#\">https://abuad-finance.org/pay-now</a></p><p>Bursary Department<br/>ABUAD</p></div>","is_phishing":true,"correct_feedback":"Good catch! The domain abuad-finance.org is fake (not abuad.edu.ng), the 48-hour threat creates urgency, and the university handles fees through the official portal, not random links.","incorrect_feedback":"This is phishing. The domain abuad-finance.org is not the real university domain. The 48-hour ultimatum is a classic urgency tactic. Fee payments are handled through the official portal.","principle":"urgency","difficulty":1},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD NACOS Chapter &lt;nacos@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> NACOS Week: Registration Now Open</p><hr/><p>Dear Computing Students,</p><p>NACOS Week holds 5th to 9th May 2025. Events include a coding competition, career fair, and guest lectures.</p><p>To register, visit the NACOS desk at the Department of Computing office during working hours.</p><p>NACOS ABUAD Chapter</p></div>","is_phishing":false,"correct_feedback":"Correct — legitimate. The domain is the real abuad.edu.ng, no suspicious links, and registration is in person at a known campus location.","incorrect_feedback":"This is legitimate. Real abuad.edu.ng domain, no links to click, registration is done in person. Not every institutional email is a trap.","principle":"social_proof","difficulty":1},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Free WiFi Promo &lt;promo@abuad-campus.org&gt;</p><p><strong>Subject:</strong> Free 5GB Data: Exclusive for ABUAD Students</p><hr/><p>Dear Student,</p><p>ABUAD in partnership with MTN Nigeria is offering <strong>free 5GB data bundles</strong> to the first 500 students who sign up.</p><p>Claim your free data now:</p><p><a href=\"#\">https://abuad-campus.org/free-data</a></p><p>Hurry — 347 students have already claimed theirs!</p></div>","is_phishing":true,"correct_feedback":"Well done! Scarcity (first 500, 347 claimed) combined with an irresistible offer. The domain abuad-campus.org is fake, and universities do not run data giveaways through email links.","incorrect_feedback":"This is phishing. The domain abuad-campus.org is fake. The free data offer is bait, the scarcity (first 500) and social proof (347 claimed) are pressure tactics working together.","principle":"scarcity","difficulty":1},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> Scholarship Board &lt;scholarships@abuad-grants.org&gt;</p><p><strong>Subject:</strong> Congratulations! You Have Been Shortlisted</p><hr/><p>Dear Student,</p><p>You have been shortlisted for the ABUAD Academic Excellence Award. To confirm your acceptance and provide your bank details for stipend disbursement, please fill the form below:</p><p><a href=\"#\">https://abuad-grants.org/acceptance-form</a></p><p>Deadline: 48 hours from receipt of this email.</p></div>","is_phishing":true,"correct_feedback":"Well spotted! The domain abuad-grants.org is fake, the email asks for bank details (universities never do this via email), and the 48-hour deadline creates urgency.","incorrect_feedback":"This is phishing. The domain is fake, universities never collect bank details via email links, and the deadline is an urgency tactic.","principle":"scarcity","difficulty":2},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Wifi Admin &lt;wifi@abuad-network.com&gt;</p><p><strong>Subject:</strong> Re-authenticate Your Campus WiFi Access</p><hr/><p>Dear Student,</p><p>Due to a system upgrade, all students must re-authenticate their campus WiFi login credentials. Failure to do so within 24 hours will result in disconnection.</p><p>Re-authenticate here: <a href=\"#\">https://abuad-network.com/wifi-auth</a></p><p>Over 800 students have already completed this process.</p></div>","is_phishing":true,"correct_feedback":"Good eye! The domain abuad-network.com is fake. This email stacks three tactics: authority (network admin), urgency (24 hours), and social proof (800 students). Real WiFi issues go through IT at abuad.edu.ng.","incorrect_feedback":"This is phishing combining three tactics at once: authority, urgency, and social proof. The domain abuad-network.com is not the real university domain.","principle":"social_proof","difficulty":2},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> Course Adviser &lt;courseadviser@abuad-academic.net&gt;</p><p><strong>Subject:</strong> Your Course Load Needs Adjustment</p><hr/><p>Dear Student,</p><p>After reviewing your registration, I noticed you have exceeded the maximum credit load. This may affect your exam eligibility.</p><p>Log in to review your courses:</p><p><a href=\"#\">https://abuad-academic.net/course-adjustment</a></p><p>Do this before the end of the week.</p><p>Your Course Adviser</p></div>","is_phishing":true,"correct_feedback":"Good catch! The domain abuad-academic.net is fake. A real course adviser would use @abuad.edu.ng, use their actual name, and likely ask you to visit their office.","incorrect_feedback":"This is phishing. The domain is fake, the sender uses a vague title instead of a real name, and a real adviser would use @abuad.edu.ng.","principle":"authority","difficulty":2},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD ICT Unit &lt;ict@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> Scheduled Maintenance: Portal Downtime</p><hr/><p>Dear Students,</p><p>The student portal will undergo scheduled maintenance on Saturday, 19th April, from 12:00 AM to 6:00 AM.</p><p>During this period, you will not be able to access the portal, check results, or register courses.</p><p>We apologise for any inconvenience.</p><p>ICT Unit<br/>Afe Babalola University</p></div>","is_phishing":false,"correct_feedback":"Correct — legitimate. The real abuad.edu.ng domain is used, the email is purely informational (no links, no requests), and it describes routine maintenance with specific times.","incorrect_feedback":"This is legitimate. Real domain, no links, no requests for action — just a routine maintenance notification. Informational emails like this are common and safe.","principle":"authority","difficulty":2},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Student Union &lt;studentunion@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> Student Union Elections: Voting Opens Monday</p><hr/><p>Dear Students,</p><p>Student Union elections will hold on Monday, 28th April. Voting will take place at the Student Centre from 9 AM to 4 PM.</p><p>Please come with your student ID card. Each student is entitled to one vote.</p><p>Student Union Electoral Committee<br/>ABUAD</p></div>","is_phishing":false,"correct_feedback":"Correct — legitimate. Real abuad.edu.ng domain, no links, no credentials requested, and it directs you to a physical location.","incorrect_feedback":"This is legitimate. Real domain, no links, physical-location-based activity. Learning to trust safe emails is just as important as spotting fakes.","principle":"social_proof","difficulty":2},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Vice-Chancellor &lt;vc@abuad.edu.com&gt;</p><p><strong>Subject:</strong> Mandatory Student Survey</p><hr/><p>Dear Student,</p><p>As part of our continuous improvement process, all students are required to complete a brief satisfaction survey.</p><p>Complete the survey here: <a href=\"#\">https://abuad.edu.com/survey</a></p><p>We appreciate your participation.</p><p>Prof. M. Adesina<br/>Vice-Chancellor<br/>Afe Babalola University, Ado-Ekiti</p></div>","is_phishing":true,"correct_feedback":"Excellent! The domain is abuad.edu.com — very close to abuad.edu.ng but not right (.com vs .edu.ng). The content is professional and plausible, but the domain gives it away. Always verify the exact TLD.","incorrect_feedback":"This is phishing. The domain abuad.edu.com is NOT the same as the real abuad.edu.ng. The difference (.com vs .edu.ng) is subtle but critical. Always check the exact domain.","principle":"authority","difficulty":3},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Data Protection &lt;dpo@abuad.edu.com&gt;</p><p><strong>Subject:</strong> NDPR Compliance: Update Your Privacy Settings</p><hr/><p>Dear Student,</p><p>In compliance with the Nigeria Data Protection Regulation (NDPR), the university is updating its data handling practices. All students must review and update their privacy settings by month end.</p><p>Review your settings: <a href=\"#\">https://abuad.edu.com/privacy-settings</a></p><p>Non-compliance may restrict access to certain university services.</p><p>Data Protection Office<br/>Afe Babalola University, Ado-Ekiti</p></div>","is_phishing":true,"correct_feedback":"Sharp eye! Despite the convincing NDPR reference (a real regulation), the domain abuad.edu.com is fake (.com not .edu.ng). The mandatory language and service restriction threat are pressure tactics.","incorrect_feedback":"This is phishing. The NDPR reference is real, but the domain abuad.edu.com is not the university domain (.edu.ng). Official compliance requests would come from @abuad.edu.ng.","principle":"authority","difficulty":3},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD E-Learning &lt;elearning@abuad-lms.edu.ng&gt;</p><p><strong>Subject:</strong> New Course Materials Available on Your LMS</p><hr/><p>Dear Student,</p><p>New course materials for CSC 402 have been uploaded to your Learning Management System. Your lecturer has also scheduled a live session for Thursday at 2:00 PM.</p><p>Access your dashboard: <a href=\"#\">https://abuad-lms.edu.ng/dashboard</a></p><p>Please review the materials before the session.</p><p>ABUAD E-Learning Unit</p></div>","is_phishing":true,"correct_feedback":"Tricky! The domain abuad-lms.edu.ng looks convincing (it uses .edu.ng), but it is a completely different domain from abuad.edu.ng. The real LMS would be at lms.abuad.edu.ng (a subdomain), not abuad-lms.edu.ng (a separate domain).","incorrect_feedback":"This is phishing! abuad-lms.edu.ng is NOT the same as abuad.edu.ng. The attacker registered a separate .edu.ng domain. The real LMS would be a subdomain like lms.abuad.edu.ng. This is a sophisticated domain trick.","principle":"authority","difficulty":3},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> Registrar &lt;registrar@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> Important: Convocation Ceremony Information</p><hr/><p>Dear Final Year Students,</p><p>The 10th Convocation Ceremony has been scheduled for Saturday, 21st June 2025, at the University Amphitheatre by 10:00 AM.</p><p>Graduating students should collect gowns from the Registrar''s Office between 16th and 20th June. Please bring your student ID and clearance form.</p><p>Further details will be communicated in due course.</p><p>Office of the Registrar<br/>Afe Babalola University, Ado-Ekiti</p></div>","is_phishing":false,"correct_feedback":"Correct — legitimate. Real abuad.edu.ng domain, specific logistical details about a real event, directs you to a physical office, and asks for no credentials or personal information.","incorrect_feedback":"This is legitimate. Real domain, specific event details, physical office visit required, no links or credentials requested. Legitimate emails can still mention deadlines — it does not automatically make them phishing.","principle":"authority","difficulty":3},

{"scenario_html":"<div style=\"font-family:Arial;padding:15px;\"><p><strong>From:</strong> ABUAD Counselling Centre &lt;counselling@abuad.edu.ng&gt;</p><p><strong>Subject:</strong> Stress Management Workshop Before Exams</p><hr/><p>Dear Students,</p><p>The Counselling Centre is organising a Stress Management and Wellness Workshop on Wednesday, 23rd April, at the Multipurpose Hall from 3:00 PM to 5:00 PM.</p><p>The workshop will cover study techniques, relaxation exercises, and time management strategies.</p><p>All students are welcome. No registration required.</p><p>ABUAD Counselling Centre</p></div>","is_phishing":false,"correct_feedback":"Correct — legitimate. Real abuad.edu.ng domain, a campus wellness event at a known location, no registration needed, no links, no requests for personal information.","incorrect_feedback":"This is legitimate. Real domain, known campus event, no links, no credentials needed. Being able to trust safe emails is just as important as catching dangerous ones.","principle":"authority","difficulty":3}
]',
1);
